import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton } from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import { createInterest, getInterestData, updateInterest } from 'src/components/services/InterestApi';
import GoBackComponent from 'src/utils/GoBackComponent';

const InterestForm = (props) => {

    const [formData, setFormData] = useState({ interest: "", url: "" });
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState("");
    const navigate = useNavigate();

    useEffect(() => {

    }, [])

    const handleChange = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.value.trimStart()?.replace(/  +/g, ' ') });
    };

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;
        var expression = /(https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|www\.[a-zA-Z0-9][a-zA-Z0-9-]+[a-zA-Z0-9]\.[^\s]{2,}|https?:\/\/(?:www\.|(?!www))[a-zA-Z0-9]+\.[^\s]{2,}|www\.[a-zA-Z0-9]+\.[^\s]{2,})/gi;
        var urlRegex = new RegExp(expression);
        if (!formData.interest) {
            errors['interest'] = "Please enter interest";
            formIsValid = false;
        }
        if (!formData.url) {
            errors['url'] = "Please enter url";
            formIsValid = false;
        }
        if (formData.url  && !formData.url?.match(urlRegex)) {
            errors['url'] = `Please enter a valid url`;
            formIsValid = false;
        }

        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let data = {
                interest: formData.interest?.trim(),
                url: formData?.url
            };
            let interest = {};
            if (props.type === "CREATE") {
                interest = await createInterest(data);
            } else {
                interest = await updateInterest(props.id, data)
            }
            if (interest?.code === 201 || interest?.code === 202) {
                navigate('/interest');
            }
            if(interest?.code === 409) {
                setErrorMessage(interest?.message);
            }
            setTimeout(() => {
                setErrorMessage();
            }, 2000);
        }
    };

    const getInterestDataById = async (id) => {
        let response = await getInterestData(id);
        if (response?.code === 200) {
            let data = {
                interest: response?.results?.interest,
                url: response?.results?.url
            }
            setFormData(data);
        }
    }

    useEffect(() => {
        if (props.type === "UPDATE") {
            getInterestDataById(props.id);
        }
    }, [])

    return (
        <>
            <GoBackComponent goBackData={"interest"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={8}>
                        <FormInput
                            value={formData.interest}
                            label={"Interest"}
                            name={"interest"}
                            onChange={handleChange}
                            required={true}
                            error={errors['interest']}
                        />
                        {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    </CCol>
                    <CCol md={8}>
                        <FormInput
                            value={formData.url}
                            label={"Url"}
                            name={"url"}
                            onChange={handleChange}
                            required={true}
                            error={errors['url']}
                        />
                    </CCol>

                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {props.type === "CREATE" ? "Create" : "Update"}
                        </CButton>
                    </CCol>
                </CForm>
            </div>
        </>
    );
}

export default InterestForm;
